import type { OptionPluginMapping } from "../types.js";
import { needsPluginMap } from "./needsPluginMap.js";

function describePackage(name: string): string {
  return name
    .replace("@tsparticles/", "")
    .replace(/-/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

const autoGeneratedPackages = new Set(Object.keys(needsPluginMap));

// ── Auto-generated from plugin needsPlugin() (authoritative) ──
const autoGeneratedEntries: OptionPluginMapping[] = Object.entries(needsPluginMap).flatMap(
  ([packageName, entry]) =>
    entry.optionPaths.map((optionPath) => ({
      optionPath,
      packageName,
      description: describePackage(packageName),
    }))
);

// ── Manually curated entries (interactions, updaters, interactivity modes) ──
// These supplement the auto-generated map; packages already in needsPluginMap
