// Auto-generated entries take priority; manual entries only add packages
// not covered by needsPluginMap (interactions, updaters, interactivity modes)
const additionalEntries = manualEntries.filter(
  (e) => !autoGeneratedPackages.has(e.packageName)
);

export const optionToPlugin: OptionPluginMapping[] = [
  ...autoGeneratedEntries,
  ...additionalEntries,
];
